#include <bits/stdc++.h>
using namespace std;
const int maxn=6e3+5;
int n,root,r[maxn],v[maxn],dp[maxn][2];
vector<int> g[maxn];

void dfs(int x){
	if(g[x].size()==0){
		dp[x][1]=r[x];
		dp[x][0]=0;
		return;
	}
	for(int i=0;i<g[x].size();i++)dfs(g[x][i]);
	dp[x][1]=r[x];
	for(int i=0;i<g[x].size();i++){
		dp[x][1]+=dp[g[x][i]][0];
	}
	dp[x][0]=0;
	for(int i=0;i<g[x].size();i++){
		dp[x][0]+=max(dp[g[x][i]][0],dp[g[x][i]][1]);
	}
}

int main(){
	cin>>n;
	for(int i=1;i<=n;i++)cin>>r[i];
	for(int i=1;i<n;i++){
		int l,k;
		cin>>l>>k;
		g[k].push_back(l);
		v[l]=1;
	}
	for(int i=1;i<=n;i++){
		if(!v[i]){
			root=i;
			break;
		}
	}
	dfs(root);
	cout<<max(dp[root][1],dp[root][0]);
	return 0;
}
